const convertFLOAT32 = (registers) => {
  // Combine the registers to get the 32-bit integer representation
  // Assuming big-endian format
  const combined = (registers[0] << 16) | registers[1];

  // Create a buffer and a DataView for conversion
  const buffer = new ArrayBuffer(4); // 4 bytes = 32 bits
  const view = new DataView(buffer);

  // Store the combined integer in the DataView as a 32-bit integer
  // Adjust this based on the actual endianness
  view.setUint32(0, combined, false); // 'false' for big-endian, 'true' for little-endian

  // Now read the value back as a float
  const floatValue = view.getFloat32(0, false); // Match the endianness

  return floatValue;
};


