    return null;
}

let excludedDays = [];
if (currentKey in storedExcludedDays) {
  excludedDays = storedExcludedDays[currentKey].map((item) => item.excludedDays) // Dias pra excluir
}

// ========== CORREÇÃO #3: decide() com comparação em ms e tolerância ==========
function decide(retain, now, start, end, toleranceMs = 30000) {
  const n = now.getTime(), a = start.getTime(), b = end.getTime();
  if (!retain) {
    if (Math.abs(n - a) <= toleranceMs) return [false, true];   // ligar
    if (Math.abs(n - b) <= toleranceMs) return [true,  false];  // desligar
    return [false, false];
  } else {
    if (n >= a && n < b) return [false, true];
    return [true, false];
  }
}

const nowLocal = convertToSaoPaulo(new Date());
const today0h = startOfDayLocal(nowLocal);
const isoToday = toISODate(today0h);

// Variáveis de referência temporal para o payload
const currDate = today0h;        // hoje 00:00
const currentTimeSP = nowLocal;  // "agora" local (São Paulo)

let shouldActivate = false;
let shouldShutdown = false;

// msg.payload = schedules;

// return msg;

// ========== CORREÇÃO #2: Holiday exclusive filtering ==========
// Detecta se hoje é feriado (com safe parsing)
const isHolidayToday = (storedHolidaysDays || []).some(d => {
  const iso = safeISO(d);
  return iso && iso === isoToday;
});

// ========== AJUSTE #4: Ordenação segura por minutos ==========
if (schedules) {
  const toHM = h => {
    const [H, M] = h.split(':').map(Number);
    return H * 60 + M;
  };
  schedules = [...schedules].sort((a, b) => toHM(a.startHour) - toHM(b.startHour));
}

// Filtra schedules com base na política de feriado (ANTES do loop!)
const holidayPolicy = flow.get('holiday_policy') || 'exclusive';
if (holidayPolicy === 'exclusive') {
  schedules = (schedules || []).filter(s => !!s.holiday === isHolidayToday);

  // ========== AJUSTE #1: Feriado sem agenda ⇒ desliga ==========
  if (isHolidayToday && (!schedules || schedules.length === 0)) {
    shouldShutdown = true;
    shouldActivate = false;
  }
}

// ========== CORREÇÃO #6: Rastreia a agenda realmente aplicada ==========
let appliedSchedule = null;

// ========== AJUSTE #2: Acumula decisões para sobreposições ==========
let anyAct = false, anyShut = false;

const currWeekDay = nowLocal.toLocaleString('en-US', { weekday: 'short' }).toLowerCase();

for (const schedule of schedules) {
  // ========== CORREÇÃO #4: Constrói horários em local time ==========
  const startTime = atTimeLocal(nowLocal, schedule.startHour);
  const endTime = atTimeLocal(nowLocal, schedule.endHour);
  const days = schedule.daysWeek;
  const retain = schedule.retain;
  const isHolidaySchedule = schedule.holiday;

  // ========== CORREÇÃO #4: Midnight crossing com local time ==========
  const crossesMidnight = startTime.getTime() > endTime.getTime();

  if (crossesMidnight) {
    const yesterday = subtractWeekDay(currWeekDay);
    let acted = false;

    // Para schedules de feriado, ignora daysWeek se hoje é feriado
    const shouldCheckYesterday = (isHolidaySchedule && isHolidayToday) || (days && days[yesterday]);

    if (shouldCheckYesterday) {
      const startYesterday = new Date(startTime.getTime() - 24 * 60 * 60 * 1000);
      const [shut, act] = decide(retain, nowLocal, startYesterday, endTime);

      anyAct = anyAct || act;
      anyShut = anyShut || shut;
      acted = (act || shut);

      if (shut && nowLocal.getTime() > endTime.getTime() && (!days || !days[currWeekDay])) {
        anyShut = false; // edge case: não desliga se hoje não é habilitado
      }

      if (acted) {
        appliedSchedule = schedule; // Registra agenda aplicada
      }
    }

    const shouldCheckToday = (isHolidaySchedule && isHolidayToday) || (days && days[currWeekDay]);

    if (!acted && shouldCheckToday) {
      const endTomorrow = new Date(endTime.getTime() + 24 * 60 * 60 * 1000);
      const [shut, act] = decide(retain, nowLocal, startTime, endTomorrow);

      anyAct = anyAct || act;
      anyShut = anyShut || shut;

      if (act || shut) {
        appliedSchedule = schedule; // Registra agenda aplicada
      }
    }
  } else {
    // Para schedules de feriado, ignora daysWeek se hoje é feriado
    const shouldExecute = (isHolidaySchedule && isHolidayToday) || (days && days[currWeekDay]);

    if (shouldExecute) {
      const [shut, act] = decide(retain, nowLocal, startTime, endTime);

      anyAct = anyAct || act;
      anyShut = anyShut || shut;

      if (act || shut) {
        appliedSchedule = schedule; // Registra agenda aplicada
      }
    }
  }

}
node.warn({device: device.deviceName, anyAct, anyShut, schedules});

// ========== AJUSTE #2: Resolve decisão consolidada ==========
if (anyAct && !anyShut) {
  shouldActivate = true;
  shouldShutdown = false;
} else if (!anyAct && anyShut) {
  shouldActivate = false;
  shouldShutdown = true;
} else if (anyAct && anyShut) {
  // Precedência: desligar vence
  shouldActivate = false;
  shouldShutdown = true;
}

// ========== CORREÇÃO #5: excludedDays sempre sobrepõe (em YYYY-MM-DD) ==========
if (Array.isArray(excludedDays) && excludedDays.length) {
  for (const ex of excludedDays) {
    const iso = safeISO(ex);
    if (iso && iso === isoToday) {
      shouldShutdown = true;
      shouldActivate = false;
      break;
    }
  }
}

if (currIndex >= (keys.length -1)) {
  currIndex = 0;
} else {
  currIndex += 1;
}

this.currIndex = currIndex;

// ========== OBSERVABILIDADE: Prepara dados APENAS quando há ação ==========
let observability = null;

// Só gera observabilidade quando houver decisão de ligar/desligar
if (shouldActivate || shouldShutdown) {
  const timestamp = Date.now();
  const deviceName = device.deviceName || 'unknown';
  const logKey = `automation_log_${deviceName.replace(/\s+/g, '')}_${timestamp}`;

  // ========== AJUSTE #5: Reason refinado com holiday_no_schedule ==========
  let reason = 'weekday';
  if (isHolidayToday) {
    reason = 'holiday';
  }
  if (isHolidayToday && (!schedules || schedules.length === 0)) {
    reason = 'holiday_no_schedule';
  }
  if (Array.isArray(excludedDays) && excludedDays.some(ex => safeISO(ex) === isoToday)) {
    reason = 'excluded';
  }

  // ========== CORREÇÃO #6: Usa a agenda REALMENTE aplicada ==========
  observability = {
    logKey: logKey,
    logData: {
      device: deviceName,
      deviceId: device.deviceId || currentKey,
      action: shouldActivate ? 'ON' : 'OFF',
      shouldActivate: shouldActivate,
      shouldShutdown: shouldShutdown,
      reason: reason,
      schedule: appliedSchedule ? {
        startHour: appliedSchedule.startHour,
        endHour: appliedSchedule.endHour,
        retain: appliedSchedule.retain,
        holiday: appliedSchedule.holiday || false,
        daysWeek: appliedSchedule.daysWeek
      } : null,
      context: {
        isHolidayToday: isHolidayToday,
        currentWeekDay: currWeekDay,
        holidayPolicy: holidayPolicy,
        totalSchedules: schedules ? schedules.length : 0
      },
      timestamp: nowLocal.toISOString(),
      timestampMs: timestamp
    }
  };
}
// ========== FIM OBSERVABILIDADE ==========

// ========== Return ==========
const returnPayload = {
  // atalhos de conveniência no topo (para quem usar direto)
  deviceName: device.deviceName,
  shouldActivate,
  shouldShutdown,

  // contrato oficial via payload
  payload: {
    currentIndex: currIndex,
    length: keys.length,

    // flags principais (contrato que Mesquita já usa)
    shouldActivate,
    shouldShutdown,

    // contexto do device
    device,
    deviceName: device.deviceName,

    // calendários
    excludedDays,
    storedHolidaysDays,

    // datas de referência
    currDate,       // hoje 00:00
    currentTimeSP,  // "agora" local

    // schedules já filtrados/aplicáveis
    schedules,
  },
};

// Adiciona observabilidade APENAS quando houver ação de agendamento
if (observability) {
  returnPayload.payload._observability = observability;
}

return returnPayload;

/**
 * func-003-LogCleanup.js
 *
 * Automatic cleanup of old automation logs
 * Keeps only logs from the last 4 days (D-3, D-2, D-1, D0)
 *
 * Recommended execution: 1x per day (e.g., 02:00 AM)
 * Can be triggered by inject node with cron
 *
 * @see LOG-RETENTION-STRATEGY.md
 */

try {
    // Configuration: how many days to keep
    const DAYS_TO_KEEP = 4; // D-3, D-2, D-1, D0

    // Get current logs
    let storedLogs = flow.get('automation_logs') || {};
    const totalBefore = Object.keys(storedLogs).length;

    // Calculate cutoff date (D-3 = today - 3 days at 00:00:00)
    const now = new Date();
    const cutoffDate = new Date(now);
    cutoffDate.setDate(cutoffDate.getDate() - (DAYS_TO_KEEP - 1));
    cutoffDate.setHours(0, 0, 0, 0);
    const cutoffTimestamp = cutoffDate.getTime();

    node.log(`Starting log cleanup. Cutoff date: ${cutoffDate.toISOString()} (keeping logs >= this date)`);

    // Filter logs, keeping only recent ones
    const filteredLogs = {};
    let deletedCount = 0;

    for (const [key, logData] of Object.entries(storedLogs)) {
        // Extract timestamp from log
        // Key format: automation_log_DeviceName_timestamp
        const timestampMatch = key.match(/_(\d+)$/);

        if (!timestampMatch) {
            // If no timestamp in key, try to get from logData
            const logTimestamp = logData.timestampMs || logData.timestamp;

            if (!logTimestamp) {
                // No timestamp, keep for safety
                filteredLogs[key] = logData;
                continue;
            }

            const logDate = typeof logTimestamp === 'number'
                ? logTimestamp
                : new Date(logTimestamp).getTime();

            if (logDate >= cutoffTimestamp) {
                filteredLogs[key] = logData;
            } else {
                deletedCount++;
            }
        } else {
            const logTimestamp = parseInt(timestampMatch[1], 10);

            // Keep if >= cutoff date
            if (logTimestamp >= cutoffTimestamp) {
                filteredLogs[key] = logData;
            } else {
                deletedCount++;
            }
        }
    }

    // Update flow with filtered logs
    flow.set('automation_logs', filteredLogs);

    const totalAfter = Object.keys(filteredLogs).length;

    // Statistics
    const stats = {
        totalBefore,
        totalAfter,
        deleted: deletedCount,
        retained: totalAfter,
        cutoffDate: cutoffDate.toISOString(),
        daysKept: DAYS_TO_KEEP,
        executedAt: now.toISOString()
    };

    node.log(`Log cleanup completed: ${deletedCount} logs deleted, ${totalAfter} logs retained`);

    // Return statistics
    msg.payload = {
        success: true,
        stats
    };

    return msg;

} catch (e) {
    node.error('Error in LogCleanup: ' + e.message);
    msg.payload = {
        success: false,
        error: e.message
    };
    return msg;
}

/**
 * func-004-TelemetryAdapter.js
 *
 * Transforms automation log events into ThingsBoard telemetry format.
 * Receives output from func-002-PersistAdapter and formats it for MQTT transmission.
 *
 * Input: { payload: { key: string, value: LogData } }
 * Output: { payload: { [deviceName]: [{ ts: number, values: { automation_log: object } }] } }
 *
 * @see RFC-0001-telemetry-automation-logs.md for detailed specification
 */

/**
 * Main telemetry adapter function
 * Transforms persisted automation logs into ThingsBoard telemetry format
 */
function telemetryAdapter(msg, node) {
    try {
        // Validate input
        if (!msg || !msg.payload) {
            node.warn('TelemetryAdapter: Missing message payload');
            return null;
        }

        const logData = msg.payload.value;

        // Validate log data
        if (!logData) {
            node.warn('TelemetryAdapter: Missing log data in payload.value');
            return null;
        }

        // Extract device name
        const deviceName = logData.device;
        if (!deviceName) {
            node.error('TelemetryAdapter: Missing device name in log data');
            return null;
        }

        // Extract timestamp (with fallback)
        const timestampMs = logData.timestampMs || Date.now();

        // Build automation_log object (excluding device name and timestamp)
        const automation_log = {
            action: logData.action,
            shouldActivate: logData.shouldActivate,
            shouldShutdown: logData.shouldShutdown,
            reason: logData.reason
        };

        // Include schedule if present
        if (logData.schedule) {
            automation_log.schedule = logData.schedule;
        }

        // Include context if present (optional - can be verbose)
        // Uncomment if context is needed in ThingsBoard
        // if (logData.context) {
        //     automation_log.context = logData.context;
        // }

        // Format as ThingsBoard telemetry
        const telemetryMap = {};
        telemetryMap[deviceName] = [{
            ts: timestampMs,
            values: {
                automation_log: automation_log
            }
        }];

        // Log successful transformation
        node.log(`TelemetryAdapter: Formatted telemetry for device "${deviceName}" - action: ${logData.action}`);

        // Return formatted message
        msg.payload = telemetryMap;
        return msg;

    } catch (error) {
        node.error(`TelemetryAdapter: Error transforming log - ${error.message}`);
        return null;
    }
}

// Node-RED function execution
const result = telemetryAdapter(msg, node);
return result;

// Skip if not a compressor
if (msg.slave.name.indexOf('COMP') < 0) {
    return null;
}

// Determine if inverted
var isInverted = false;
var deviceConfig = msg.slave.toJSON();
for (var i = 0; i < deviceConfig.channels_list.length; i++) {
    var channel = deviceConfig.channels_list[i];
    if (channel.type === 'inverted_actionable') {
        isInverted = true;
        break;
    }
}

// Get current compressores or initialize empty object
var compressores = flow.get('compressores') || {};

// Process each compressor in payload
for (var name in msg.payload) {
    if (msg.payload.hasOwnProperty(name)) {
        var data = msg.payload[name];
        var status = data[0] && data[0].values && data[0].values.status;

        // Convert status to boolean (true = on, false = off)
        var isOn = status === 'on';

        // If inverted, flip the value
        if (isInverted) {
            isOn = !isOn;
        }

        compressores[name] = isOn;
    }
}

// Save back to flow context
flow.set('compressores', compressores);

return msg;
